async function main() {
  printBanner();

  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
    prompt: "\n🔮 Describe your automation > ",
  });

  rl.prompt();

  rl.on("line", async (line) => {
    await handleUserInput(line);
    rl.prompt();
  });

  rl.on("close", () => {
    console.log(
      "\n👋 Goodbye! Thanks for using the no-code automation platform.\n"
    );
    process.exit(0);
  });
}

main().catch(console.error);